// src/components/AuthModal.jsx
import { useState } from "react";
import {
  signInWithEmail, signUpWithEmail,
  signInWithGoogle, resetPassword,
} from "../firebase/auth";

const TABS = ["login", "signup", "reset"];

export default function AuthModal({ onClose, onSuccess }) {
  const [tab, setTab]           = useState("login");
  const [name, setName]         = useState("");
  const [email, setEmail]       = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading]   = useState(false);
  const [error, setError]       = useState("");
  const [resetSent, setResetSent] = useState(false);

  const clear = () => { setError(""); };

  const handleSubmit = async () => {
    clear();
    if (!email) { setError("Email is required."); return; }
    setLoading(true);
    try {
      if (tab === "login") {
        await signInWithEmail(email, password);
      } else if (tab === "signup") {
        if (!name.trim()) { setError("Name is required."); setLoading(false); return; }
        if (password.length < 6) { setError("Password must be 6+ characters."); setLoading(false); return; }
        await signUpWithEmail(email, password, name.trim());
      } else {
        await resetPassword(email);
        setResetSent(true);
        setLoading(false);
        return;
      }
      onSuccess?.();
      onClose();
    } catch (e) {
      const msgs = {
        "auth/user-not-found":    "No account found with this email.",
        "auth/wrong-password":    "Incorrect password.",
        "auth/email-already-in-use": "Email already registered. Try logging in.",
        "auth/invalid-email":     "Invalid email address.",
        "auth/weak-password":     "Password must be at least 6 characters.",
        "auth/too-many-requests": "Too many attempts. Please try again later.",
        "auth/popup-closed-by-user": "Google sign-in was cancelled.",
      };
      setError(msgs[e.code] || e.message);
    }
    setLoading(false);
  };

  const handleGoogle = async () => {
    clear(); setLoading(true);
    try {
      await signInWithGoogle();
      onSuccess?.(); onClose();
    } catch (e) {
      setError(e.message);
    }
    setLoading(false);
  };

  const tabLabel = { login: "Welcome back", signup: "Create account", reset: "Reset password" };

  return (
    <div style={s.backdrop} onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div style={s.modal}>
        {/* Close */}
        <button style={s.closeBtn} onClick={onClose}>✕</button>

        {/* Brand */}
        <div style={s.brand}>
          <span style={s.brandName}>AERO<span style={{ color: "var(--blue)" }}>BLOG</span></span>
          <span style={s.brandDot} />
        </div>

        {/* Tabs */}
        <div style={s.tabs}>
          {["login", "signup"].map((t) => (
            <button key={t} style={{ ...s.tab, ...(tab === t ? s.tabActive : {}) }}
              onClick={() => { setTab(t); clear(); setResetSent(false); }}>
              {t === "login" ? "Log In" : "Sign Up"}
            </button>
          ))}
        </div>

        <h2 style={s.heading}>{tabLabel[tab]}</h2>
        <p style={s.sub}>
          {tab === "login"  && "Sign in to publish, comment & join the community."}
          {tab === "signup" && "Join AERO BLOG — it's free forever."}
          {tab === "reset"  && "We'll email you a password reset link."}
        </p>

        {/* Google btn */}
        {tab !== "reset" && (
          <button style={s.googleBtn} onClick={handleGoogle} disabled={loading}>
            <svg width="18" height="18" viewBox="0 0 48 48">
              <path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.72 17.74 9.5 24 9.5z"/>
              <path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/>
              <path fill="#FBBC05" d="M10.53 28.59c-.48-1.45-.76-2.99-.76-4.59s.27-3.14.76-4.59l-7.98-6.19C.92 16.46 0 20.12 0 24c0 3.88.92 7.54 2.56 10.78l7.97-6.19z"/>
              <path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.15 1.45-4.92 2.3-8.16 2.3-6.26 0-11.57-4.22-13.47-9.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"/>
            </svg>
            Continue with Google
          </button>
        )}

        {tab !== "reset" && <div style={s.divider}><span>or</span></div>}

        {/* Fields */}
        <div style={s.fields}>
          {tab === "signup" && (
            <div style={s.field}>
              <label style={s.label}>Display Name</label>
              <input style={s.input} placeholder="Your name" value={name}
                onChange={(e) => setName(e.target.value)} />
            </div>
          )}
          <div style={s.field}>
            <label style={s.label}>Email</label>
            <input style={s.input} type="email" placeholder="you@example.com"
              value={email} onChange={(e) => setEmail(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleSubmit()} />
          </div>
          {tab !== "reset" && (
            <div style={s.field}>
              <label style={s.label}>
                Password
                {tab === "login" && (
                  <button style={s.forgotBtn}
                    onClick={() => { setTab("reset"); clear(); }}>
                    Forgot?
                  </button>
                )}
              </label>
              <input style={s.input} type="password" placeholder="••••••••"
                value={password} onChange={(e) => setPassword(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && handleSubmit()} />
            </div>
          )}
        </div>

        {/* Error */}
        {error && <div style={s.error}>⚠️ {error}</div>}

        {/* Reset sent */}
        {resetSent && (
          <div style={s.success}>
            ✅ Reset link sent! Check your inbox.
          </div>
        )}

        {/* Submit */}
        {!resetSent && (
          <button style={{ ...s.submitBtn, opacity: loading ? 0.7 : 1 }}
            onClick={handleSubmit} disabled={loading}>
            {loading ? <><span style={s.spinner} /> Working…</> :
              tab === "login"  ? "Log In →" :
              tab === "signup" ? "Create Account →" :
              "Send Reset Link →"}
          </button>
        )}

        {/* Switch tab */}
        <p style={s.switchText}>
          {tab === "login" ? (
            <>No account? <button style={s.switchBtn} onClick={() => { setTab("signup"); clear(); }}>Sign up free</button></>
          ) : tab === "signup" ? (
            <>Already a member? <button style={s.switchBtn} onClick={() => { setTab("login"); clear(); }}>Log in</button></>
          ) : (
            <button style={s.switchBtn} onClick={() => { setTab("login"); clear(); setResetSent(false); }}>← Back to login</button>
          )}
        </p>
      </div>
    </div>
  );
}

